// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

// ─── Interfaces ───────────────────────────────────────────────────────────────

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/// @dev Permit2 AllowanceTransfer
interface IPermit2 {
    function transferFrom(address from, address to, uint160 amount, address token) external;
}

/// @dev Uniswap V3 Pool (World Chain specific factory)
interface IUniswapV3Pool {
    function swap(
        address recipient,
        bool zeroForOne,
        int256 amountSpecified,
        uint160 sqrtPriceLimitX96,
        bytes calldata data
    ) external returns (int256 amount0, int256 amount1);
    function token0() external view returns (address);
    function token1() external view returns (address);
    function fee() external view returns (uint24);
    function slot0() external view returns (
        uint160 sqrtPriceX96, int24 tick, uint16, uint16, uint16, uint8, bool
    );
}

/// @dev Uniswap V3 Swap Callback
interface IUniswapV3SwapCallback {
    function uniswapV3SwapCallback(
        int256 amount0Delta,
        int256 amount1Delta,
        bytes calldata data
    ) external;
}

/// @dev Uniswap V2 Router (Uniswap V2 on World Chain)
interface ISwapRouterV2 {
    function swapExactTokensForTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external returns (uint256[] memory amounts);
    function getAmountsOut(uint amountIn, address[] memory path)
        external view returns (uint[] memory amounts);
}

/// @dev Volume tracking
interface IVolumeRewards {
    function recordSwap(address user, uint256 usdcAmount) external;
}

// ─── AcuaSwapRouter ───────────────────────────────────────────────────────────

/**
 * @title AcuaSwapRouter
 * @notice On-chain fee wrapper for Uniswap V3 (direct pool calls) and V2 on World Chain.
 *         Uses Permit2 AllowanceTransfer for token pulls.
 *         Calls World Chain V3 pools directly (factory = 0x7a5028...) since the standard
 *         SwapRouter02 is deployed with the Ethereum mainnet factory address.
 *
 * Fee model:
 *   swapFeeBps (default 200 = 2%) — split evenly among feeOwners
 *   h2oFeeBps  (default 10  = 0.1%) — pooled for periodic H2O buyback
 */
contract AcuaSwapRouter is IUniswapV3SwapCallback {

    // ─── Constants ────────────────────────────────────────────────────────────
    IPermit2 public constant PERMIT2 = IPermit2(0x000000000022D473030F116dDEE9F6B43aC78BA3);

    /// @dev World Chain Uniswap V3 factory (different from Ethereum mainnet)
    address public constant V3_FACTORY    = 0x7a5028BDa40e7B173C278C5342087826455ea25a;
    bytes32 public constant V3_POOL_INIT_CODE_HASH =
        0xe34f199b19b2b4f47f68442619d555527d244f78a3297ea89325f843f87b8b54;

    /// @dev Standard Uniswap V2 router deployed on World Chain
    ISwapRouterV2 public constant ROUTER_V2 = ISwapRouterV2(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);

    address public constant H2O  = 0x17392e5483983945dEB92e0518a8F2C4eB6bA59d;
    address public constant WLD  = 0x2cFc85d8E48F8EAB294be644d9E25C3030863003;
    address public constant USDC = 0x79A02482A880bCE3F13e09Da970dC34db4CD24d1;

    uint160 private constant _MIN_SQRT_RATIO = 4295128739;
    uint160 private constant _MAX_SQRT_RATIO = 1461446703485210103287273052203988822378723970342;
    uint256 public  constant MAX_FEE_BPS = 1000;

    // ─── Config ───────────────────────────────────────────────────────────────
    address   public owner;
    address[3] public feeOwners;
    uint256   public swapFeeBps = 200;
    uint256   public h2oFeeBps  = 10;
    address   public volumeRewards;

    // ─── Fee accounting ───────────────────────────────────────────────────────
    mapping(address => mapping(address => uint256)) public ownerFees;
    mapping(address => uint256) public h2oFeePool;

    // ─── Transient swap context (re-entrant callback) ─────────────────────────
    address private _swapUser;
    address private _swapToken;

    // ─── Events ───────────────────────────────────────────────────────────────
    event SwappedV3(address indexed user, address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOut);
    event SwappedV2(address indexed user, address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOut);
    event FeeClaimed(address indexed who, address indexed token, uint256 amount);
    event H2OBought(address indexed token, uint256 tokenIn, uint256 h2oOut);
    event ConfigUpdated();

    modifier onlyOwner() { require(msg.sender == owner, "Not owner"); _; }

    // ─── Constructor ──────────────────────────────────────────────────────────
    constructor(address[3] memory _feeOwners) {
        owner = msg.sender;
        feeOwners = _feeOwners;
    }

    // ─── Pool address computation ─────────────────────────────────────────────
    function _computePool(address tokenA, address tokenB, uint24 fee)
        internal pure returns (address pool)
    {
        (address t0, address t1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        bytes32 salt = keccak256(abi.encode(t0, t1, fee));
        pool = address(uint160(uint256(keccak256(abi.encodePacked(
            bytes1(0xff), V3_FACTORY, salt, V3_POOL_INIT_CODE_HASH
        )))));
    }

    // ─── V3 Swap Callback ─────────────────────────────────────────────────────
    /**
     * @dev Called by the pool after our swap() call. We push owed tokens from our balance.
     *      The router holds the net amount (after fees) at this point.
     */
    function uniswapV3SwapCallback(
        int256 amount0Delta,
        int256 amount1Delta,
        bytes calldata /* data */
    ) external override {
        // The caller must be the pool we computed (security check)
        require(_swapToken != address(0), "No active swap");
        // We already hold the net token amount, just transfer it to the pool
        if (amount0Delta > 0) {
            IERC20(_swapToken).transfer(msg.sender, uint256(amount0Delta));
        } else if (amount1Delta > 0) {
            IERC20(_swapToken).transfer(msg.sender, uint256(amount1Delta));
        }
    }

    // ─── Internal fee deduction ───────────────────────────────────────────────
    function _deductFees(address token, uint256 amount) internal returns (uint256 netAmount) {
        uint256 swapFee = amount * swapFeeBps / 10000;
        uint256 h2oFee  = amount * h2oFeeBps  / 10000;

        if (swapFee > 0) {
            uint256 active;
            for (uint256 i; i < 3; ++i) if (feeOwners[i] != address(0)) ++active;
            if (active > 0) {
                uint256 per = swapFee / active;
                uint256 dust = swapFee - per * active;
                for (uint256 i; i < 3; ++i)
                    if (feeOwners[i] != address(0)) ownerFees[feeOwners[i]][token] += per;
                ownerFees[feeOwners[0]][token] += dust;
            } else {
                ownerFees[owner][token] += swapFee;
            }
        }
        if (h2oFee > 0) h2oFeePool[token] += h2oFee;
        netAmount = amount - swapFee - h2oFee;
    }

    // ─── Swap via Uniswap V3 (direct pool, single hop) ────────────────────────
    /**
     * @param tokenIn         Input token
     * @param tokenOut        Output token
     * @param fee             Pool fee tier (100, 500, 3000, or 10000)
     * @param amountIn        Gross input amount (fees deducted on-chain)
     * @param amountOutMin    Minimum output after slippage
     * @param usdcEquivalent  Input value in USDC-6-dec for volume tracking
     */
    function swapV3Single(
        address tokenIn,
        address tokenOut,
        uint24  fee,
        uint256 amountIn,
        uint256 amountOutMin,
        uint256 usdcEquivalent
    ) external returns (uint256 amountOut) {
        require(amountIn > 0 && amountIn <= type(uint160).max, "Bad amount");

        // Pull tokens via Permit2
        PERMIT2.transferFrom(msg.sender, address(this), uint160(amountIn), tokenIn);

        // Deduct fees
        uint256 netAmt = _deductFees(tokenIn, amountIn);

        // Set callback context
        _swapUser  = msg.sender;
        _swapToken = tokenIn;

        address pool = _computePool(tokenIn, tokenOut, fee);
        bool zeroForOne = tokenIn < tokenOut;
        uint160 sqrtLimit = zeroForOne ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1;

        (int256 a0, int256 a1) = IUniswapV3Pool(pool).swap(
            msg.sender,        // recipient gets tokenOut
            zeroForOne,
            int256(netAmt),    // exact input
            sqrtLimit,
            ""
        );

        _swapToken = address(0); // clear callback context

        amountOut = zeroForOne ? uint256(-a1) : uint256(-a0);
        require(amountOut >= amountOutMin, "Too much slippage");

        _recordVolume(msg.sender, usdcEquivalent);
        emit SwappedV3(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    // ─── Swap via Uniswap V3 (multi-hop: tokenIn -> hop -> tokenOut) ──────────
    /**
     * @param tokenIn       Input token
     * @param hopToken      Intermediate token (WLD or USDC typically)
     * @param tokenOut      Output token
     * @param fee1          Fee tier for first hop (tokenIn -> hop)
     * @param fee2          Fee tier for second hop (hop -> tokenOut)
     * @param amountIn      Gross input
     * @param amountOutMin  Minimum output
     * @param usdcEquivalent Input USD value (6-dec)
     */
    function swapV3Multi(
        address tokenIn,
        address hopToken,
        address tokenOut,
        uint24  fee1,
        uint24  fee2,
        uint256 amountIn,
        uint256 amountOutMin,
        uint256 usdcEquivalent
    ) external returns (uint256 amountOut) {
        require(amountIn > 0 && amountIn <= type(uint160).max, "Bad amount");

        PERMIT2.transferFrom(msg.sender, address(this), uint160(amountIn), tokenIn);
        uint256 netAmt = _deductFees(tokenIn, amountIn);

        // Hop 1: tokenIn -> hopToken (output to this contract)
        _swapUser  = msg.sender;
        _swapToken = tokenIn;
        address pool1 = _computePool(tokenIn, hopToken, fee1);
        bool z1 = tokenIn < hopToken;
        (int256 a0, int256 a1) = IUniswapV3Pool(pool1).swap(
            address(this), z1, int256(netAmt), z1 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 midAmt = z1 ? uint256(-a1) : uint256(-a0);

        // Hop 2: hopToken -> tokenOut (output directly to user)
        _swapToken = hopToken;
        address pool2 = _computePool(hopToken, tokenOut, fee2);
        bool z2 = hopToken < tokenOut;
        (int256 b0, int256 b1) = IUniswapV3Pool(pool2).swap(
            msg.sender, z2, int256(midAmt), z2 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        amountOut = z2 ? uint256(-b1) : uint256(-b0);

        require(amountOut >= amountOutMin, "Too much slippage");
        _recordVolume(msg.sender, usdcEquivalent);
        emit SwappedV3(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    // ─── Swap via Uniswap V2 ──────────────────────────────────────────────────
    function swapV2(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata v2Path,
        uint256 usdcEquivalent
    ) external returns (uint256 amountOut) {
        require(amountIn > 0 && amountIn <= type(uint160).max, "Bad amount");
        require(v2Path.length >= 2, "Bad path");

        PERMIT2.transferFrom(msg.sender, address(this), uint160(amountIn), tokenIn);
        uint256 netAmt = _deductFees(tokenIn, amountIn);

        IERC20(tokenIn).approve(address(ROUTER_V2), netAmt);
        uint256[] memory amounts = ROUTER_V2.swapExactTokensForTokens(
            netAmt, amountOutMin, v2Path, msg.sender, block.timestamp + 1800
        );
        amountOut = amounts[amounts.length - 1];

        _recordVolume(msg.sender, usdcEquivalent);
        emit SwappedV2(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    // ─── Fee claims ───────────────────────────────────────────────────────────
    function claimFees(address token) external {
        uint256 amount = ownerFees[msg.sender][token];
        require(amount > 0, "Nothing to claim");
        ownerFees[msg.sender][token] = 0;
        IERC20(token).transfer(msg.sender, amount);
        emit FeeClaimed(msg.sender, token, amount);
    }

    function claimFeesBatch(address[] calldata tokens) external {
        for (uint256 i; i < tokens.length; ++i) {
            uint256 a = ownerFees[msg.sender][tokens[i]];
            if (a == 0) continue;
            ownerFees[msg.sender][tokens[i]] = 0;
            IERC20(tokens[i]).transfer(msg.sender, a);
            emit FeeClaimed(msg.sender, tokens[i], a);
        }
    }

    // ─── H2O buyback (owner calls periodically) ───────────────────────────────
    function buybackH2O(address token, uint24 feeHop, uint24 feeOut) external onlyOwner {
        uint256 amount = h2oFeePool[token];
        require(amount > 0, "No fees");
        h2oFeePool[token] = 0;

        if (token == H2O) {
            IERC20(H2O).transfer(owner, amount);
            emit H2OBought(token, amount, amount);
            return;
        }

        // Route token -> WLD -> H2O (via V3 direct pools on World Chain)
        _swapToken = token;
        address pool1 = _computePool(token, WLD, feeHop);
        bool z1 = token < WLD;
        (int256 a0, int256 a1) = IUniswapV3Pool(pool1).swap(
            address(this), z1, int256(amount), z1 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 wldAmt = z1 ? uint256(-a1) : uint256(-a0);

        _swapToken = WLD;
        address pool2 = _computePool(WLD, H2O, feeOut);
        bool z2 = WLD < H2O;
        (int256 b0, int256 b1) = IUniswapV3Pool(pool2).swap(
            owner, z2, int256(wldAmt), z2 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 h2oOut = z2 ? uint256(-b1) : uint256(-b0);

        emit H2OBought(token, amount, h2oOut);
    }

    // ─── Helpers ──────────────────────────────────────────────────────────────
    function _recordVolume(address user, uint256 usdcAmount) internal {
        if (volumeRewards != address(0) && usdcAmount > 0) {
            try IVolumeRewards(volumeRewards).recordSwap(user, usdcAmount) {} catch {}
        }
    }

    /// @notice Preview a single-hop V3 quote (spot price, no impact — only for UI use)
    function quoteSingle(address tokenIn, address tokenOut, uint24 fee, uint256 amountIn)
        external view returns (uint256 amountOut, address poolAddr)
    {
        poolAddr = _computePool(tokenIn, tokenOut, fee);
        (uint160 sqrtPriceX96,,,,,,) = IUniswapV3Pool(poolAddr).slot0();
        // price = (sqrtPriceX96 / 2^96)^2
        // token0 price in token1: price = sqrtPriceX96^2 / 2^192
        bool zeroForOne = tokenIn < tokenOut;
        uint256 priceX192 = uint256(sqrtPriceX96) * uint256(sqrtPriceX96);
        if (zeroForOne) {
            // tokenIn = token0, tokenOut = token1
            amountOut = amountIn * priceX192 / (1 << 192);
        } else {
            // tokenIn = token1, tokenOut = token0
            amountOut = amountIn * (1 << 192) / priceX192;
        }
    }

    // ─── Admin ────────────────────────────────────────────────────────────────
    function setFees(uint256 _swapFeeBps, uint256 _h2oFeeBps) external onlyOwner {
        require(_swapFeeBps + _h2oFeeBps <= MAX_FEE_BPS, "Fee too high");
        swapFeeBps = _swapFeeBps;
        h2oFeeBps  = _h2oFeeBps;
        emit ConfigUpdated();
    }

    function setFeeOwners(address[3] calldata _owners) external onlyOwner {
        feeOwners = _owners;
        emit ConfigUpdated();
    }

    function setVolumeRewards(address _vr) external onlyOwner {
        volumeRewards = _vr;
        emit ConfigUpdated();
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero addr");
        owner = newOwner;
    }

    function emergencyWithdraw(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }

    function getPoolAddress(address tokenA, address tokenB, uint24 fee)
        external pure returns (address)
    {
        return _computePool(tokenA, tokenB, fee);
    }
}

contracts/AcuaSwapRouterV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

// ─── Interfaces ───────────────────────────────────────────────────────────────

interface IERC20V2 {
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

interface IUniswapV3Pool {
    function swap(
        address recipient,
        bool zeroForOne,
        int256 amountSpecified,
        uint160 sqrtPriceLimitX96,
        bytes calldata data
    ) external returns (int256 amount0, int256 amount1);
    function token0() external view returns (address);
    function token1() external view returns (address);
    function fee() external view returns (uint24);
    function slot0() external view returns (
        uint160 sqrtPriceX96, int24 tick, uint16, uint16, uint16, uint8, bool
    );
}

interface IUniswapV3SwapCallback {
    function uniswapV3SwapCallback(
        int256 amount0Delta,
        int256 amount1Delta,
        bytes calldata data
    ) external;
}

interface IVolumeRewards {
    function recordSwap(address user, uint256 usdcAmount) external;
}

// ─── AcuaSwapRouterV2 ─────────────────────────────────────────────────────────
/**
 * @title  AcuaSwapRouterV2
 * @notice Uniswap V3 swap router using Permit2 SignatureTransfer.
 *         Compatible with MiniKit's native permit2 field — requires only
 *         ONE transaction + one off-chain signature (no pre-approval needed).
 *
 * Fee model:
 *   swapFeeBps (default 200 = 2%)  — split evenly among feeOwners
 *   h2oFeeBps  (default 10  = 0.1%) — pooled for periodic H2O buyback
 */
contract AcuaSwapRouterV2 is IUniswapV3SwapCallback {

    // ─── Constants ────────────────────────────────────────────────────────────
    address public constant PERMIT2_ADDR = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public constant V3_FACTORY = 0x7a5028BDa40e7B173C278C5342087826455ea25a;
    bytes32 public constant V3_POOL_INIT_CODE_HASH =
        0xe34f199b19b2b4f47f68442619d555527d244f78a3297ea89325f843f87b8b54;

    address public constant H2O  = 0x17392e5483983945dEB92e0518a8F2C4eB6bA59d;
    address public constant WLD  = 0x2cFc85d8E48F8EAB294be644d9E25C3030863003;
    address public constant USDC = 0x79A02482A880bCE3F13e09Da970dC34db4CD24d1;

    uint160 private constant _MIN_SQRT_RATIO = 4295128739;
    uint160 private constant _MAX_SQRT_RATIO = 1461446703485210103287273052203988822378723970342;
    uint256 public  constant MAX_FEE_BPS = 1000;

    // ─── Config ───────────────────────────────────────────────────────────────
    address   public owner;
    address[3] public feeOwners;
    uint256   public swapFeeBps = 200;
    uint256   public h2oFeeBps  = 10;
    address   public volumeRewards;

    // ─── Fee accounting ───────────────────────────────────────────────────────
    mapping(address => mapping(address => uint256)) public ownerFees;
    mapping(address => uint256) public h2oFeePool;

    // ─── Transient swap context (re-entrant callback) ─────────────────────────
    address private _swapToken;

    // ─── Events ───────────────────────────────────────────────────────────────
    event SwappedV3(address indexed user, address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOut);
    event FeeClaimed(address indexed who, address indexed token, uint256 amount);
    event H2OBought(address indexed token, uint256 tokenIn, uint256 h2oOut);
    event ConfigUpdated();

    modifier onlyOwner() { require(msg.sender == owner, "Not owner"); _; }

    // ─── Constructor ──────────────────────────────────────────────────────────
    constructor(address[3] memory _feeOwners) {
        owner = msg.sender;
        feeOwners = _feeOwners;
    }

    // ─── Pool address computation ─────────────────────────────────────────────
    function _computePool(address tokenA, address tokenB, uint24 fee)
        internal pure returns (address pool)
    {
        (address t0, address t1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        bytes32 salt = keccak256(abi.encode(t0, t1, fee));
        pool = address(uint160(uint256(keccak256(abi.encodePacked(
            bytes1(0xff), V3_FACTORY, salt, V3_POOL_INIT_CODE_HASH
        )))));
    }

    // ─── V3 Swap Callback ─────────────────────────────────────────────────────
    function uniswapV3SwapCallback(
        int256 amount0Delta,
        int256 amount1Delta,
        bytes calldata
    ) external override {
        require(_swapToken != address(0), "No active swap");
        if (amount0Delta > 0) {
            IERC20V2(_swapToken).transfer(msg.sender, uint256(amount0Delta));
        } else if (amount1Delta > 0) {
            IERC20V2(_swapToken).transfer(msg.sender, uint256(amount1Delta));
        }
    }

    // ─── Internal fee deduction ───────────────────────────────────────────────
    function _deductFees(address token, uint256 amount) internal returns (uint256 netAmount) {
        uint256 swapFee = amount * swapFeeBps / 10000;
        uint256 h2oFee  = amount * h2oFeeBps  / 10000;

        if (swapFee > 0) {
            uint256 active;
            for (uint256 i; i < 3; ++i) if (feeOwners[i] != address(0)) ++active;
            if (active > 0) {
                uint256 per = swapFee / active;
                uint256 dust = swapFee - per * active;
                for (uint256 i; i < 3; ++i)
                    if (feeOwners[i] != address(0)) ownerFees[feeOwners[i]][token] += per;
                ownerFees[feeOwners[0]][token] += dust;
            } else {
                ownerFees[owner][token] += swapFee;
            }
        }
        if (h2oFee > 0) h2oFeePool[token] += h2oFee;
        netAmount = amount - swapFee - h2oFee;
    }

    // ─── Receive tokens via Permit2 SignatureTransfer ─────────────────────────
    function _receiveViaPermit2(
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature,
        uint256 amount
    ) internal {
        IPermit2(PERMIT2_ADDR).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails({ to: address(this), requestedAmount: amount }),
            msg.sender,
            signature
        );
    }

    // ─── Swap V3 Single hop ───────────────────────────────────────────────────
    /**
     * @param tokenOut        Output token address
     * @param fee             Uniswap V3 pool fee tier (100, 500, 3000, 10000)
     * @param amountOutMin    Minimum output (slippage protection)
     * @param usdcEquivalent  Input value in USDC-6-dec for volume tracking
     * @param permit          Permit2 SignatureTransfer permit struct
     * @param signature       Permit2 signature (provided by MiniKit)
     */
    function swapV3Single(
        address tokenOut,
        uint24  fee,
        uint256 amountOutMin,
        uint256 usdcEquivalent,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature
    ) external returns (uint256 amountOut) {
        address tokenIn = permit.permitted.token;
        uint256 amountIn = permit.permitted.amount;
        require(amountIn > 0, "Zero amount");

        // Pull tokens via Permit2 SignatureTransfer
        _receiveViaPermit2(permit, signature, amountIn);

        // Deduct fees
        uint256 netAmt = _deductFees(tokenIn, amountIn);

        // Execute V3 swap — callback will push tokens to the pool
        _swapToken = tokenIn;
        address pool = _computePool(tokenIn, tokenOut, fee);
        bool zeroForOne = tokenIn < tokenOut;
        uint160 sqrtLimit = zeroForOne ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1;

        (int256 a0, int256 a1) = IUniswapV3Pool(pool).swap(
            msg.sender, zeroForOne, int256(netAmt), sqrtLimit, ""
        );
        _swapToken = address(0);

        amountOut = zeroForOne ? uint256(-a1) : uint256(-a0);
        require(amountOut >= amountOutMin, "Too much slippage");

        _recordVolume(msg.sender, usdcEquivalent);
        emit SwappedV3(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    // ─── Swap V3 Multi hop (tokenIn -> hop -> tokenOut) ───────────────────────
    /**
     * @param hopToken        Intermediate token (e.g. WLD or USDC)
     * @param tokenOut        Final output token
     * @param fee1            Fee tier for first hop
     * @param fee2            Fee tier for second hop
     * @param amountOutMin    Minimum output
     * @param usdcEquivalent  Input USD value (6-dec)
     * @param permit          Permit2 SignatureTransfer permit struct
     * @param signature       Permit2 signature (provided by MiniKit)
     */
    function swapV3Multi(
        address hopToken,
        address tokenOut,
        uint24  fee1,
        uint24  fee2,
        uint256 amountOutMin,
        uint256 usdcEquivalent,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature
    ) external returns (uint256 amountOut) {
        address tokenIn = permit.permitted.token;
        uint256 amountIn = permit.permitted.amount;
        require(amountIn > 0, "Zero amount");

        _receiveViaPermit2(permit, signature, amountIn);
        uint256 netAmt = _deductFees(tokenIn, amountIn);

        // Hop 1: tokenIn → hopToken (output stays in this contract)
        _swapToken = tokenIn;
        address pool1 = _computePool(tokenIn, hopToken, fee1);
        bool z1 = tokenIn < hopToken;
        (int256 a0, int256 a1) = IUniswapV3Pool(pool1).swap(
            address(this), z1, int256(netAmt), z1 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 midAmt = z1 ? uint256(-a1) : uint256(-a0);

        // Hop 2: hopToken → tokenOut (output directly to user)
        _swapToken = hopToken;
        address pool2 = _computePool(hopToken, tokenOut, fee2);
        bool z2 = hopToken < tokenOut;
        (int256 b0, int256 b1) = IUniswapV3Pool(pool2).swap(
            msg.sender, z2, int256(midAmt), z2 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        amountOut = z2 ? uint256(-b1) : uint256(-b0);

        require(amountOut >= amountOutMin, "Too much slippage");
        _recordVolume(msg.sender, usdcEquivalent);
        emit SwappedV3(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    // ─── Quote (view, for UI) ─────────────────────────────────────────────────
    function quoteSingle(address tokenIn, address tokenOut, uint24 fee, uint256 amountIn)
        external view returns (uint256 amountOut, address poolAddr)
    {
        poolAddr = _computePool(tokenIn, tokenOut, fee);
        (uint160 sqrtPriceX96,,,,,,) = IUniswapV3Pool(poolAddr).slot0();
        bool zeroForOne = tokenIn < tokenOut;
        uint256 priceX192 = uint256(sqrtPriceX96) * uint256(sqrtPriceX96);
        if (zeroForOne) {
            amountOut = amountIn * priceX192 / (1 << 192);
        } else {
            amountOut = amountIn * (1 << 192) / priceX192;
        }
    }

    // ─── Fee claims ───────────────────────────────────────────────────────────
    function claimFees(address token) external {
        uint256 amount = ownerFees[msg.sender][token];
        require(amount > 0, "Nothing to claim");
        ownerFees[msg.sender][token] = 0;
        IERC20V2(token).transfer(msg.sender, amount);
        emit FeeClaimed(msg.sender, token, amount);
    }

    function claimFeesBatch(address[] calldata tokens) external {
        for (uint256 i; i < tokens.length; ++i) {
            uint256 a = ownerFees[msg.sender][tokens[i]];
            if (a == 0) continue;
            ownerFees[msg.sender][tokens[i]] = 0;
            IERC20V2(tokens[i]).transfer(msg.sender, a);
            emit FeeClaimed(msg.sender, tokens[i], a);
        }
    }

    // ─── H2O buyback ─────────────────────────────────────────────────────────
    function buybackH2O(address token, uint24 feeHop, uint24 feeOut) external onlyOwner {
        uint256 amount = h2oFeePool[token];
        require(amount > 0, "No fees");
        h2oFeePool[token] = 0;

        if (token == H2O) {
            IERC20V2(H2O).transfer(owner, amount);
            emit H2OBought(token, amount, amount);
            return;
        }

        _swapToken = token;
        address pool1 = _computePool(token, WLD, feeHop);
        bool z1 = token < WLD;
        (int256 a0, int256 a1) = IUniswapV3Pool(pool1).swap(
            address(this), z1, int256(amount), z1 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 wldAmt = z1 ? uint256(-a1) : uint256(-a0);

        _swapToken = WLD;
        address pool2 = _computePool(WLD, H2O, feeOut);
        bool z2 = WLD < H2O;
        (int256 b0, int256 b1) = IUniswapV3Pool(pool2).swap(
            owner, z2, int256(wldAmt), z2 ? _MIN_SQRT_RATIO + 1 : _MAX_SQRT_RATIO - 1, ""
        );
        _swapToken = address(0);
        uint256 h2oOut = z2 ? uint256(-b1) : uint256(-b0);

        emit H2OBought(token, amount, h2oOut);
    }

    // ─── Helpers ──────────────────────────────────────────────────────────────
    function _recordVolume(address user, uint256 usdcAmount) internal {
        if (volumeRewards != address(0) && usdcAmount > 0) {
            try IVolumeRewards(volumeRewards).recordSwap(user, usdcAmount) {} catch {}
        }
    }

    function getPoolAddress(address tokenA, address tokenB, uint24 fee)
        external pure returns (address)
    {
        return _computePool(tokenA, tokenB, fee);
    }

    // ─── Admin ────────────────────────────────────────────────────────────────
    function setFees(uint256 _swapFeeBps, uint256 _h2oFeeBps) external onlyOwner {
        require(_swapFeeBps + _h2oFeeBps <= MAX_FEE_BPS, "Fee too high");
        swapFeeBps = _swapFeeBps;
        h2oFeeBps  = _h2oFeeBps;
        emit ConfigUpdated();
    }

    function setFeeOwners(address[3] calldata _owners) external onlyOwner {
        feeOwners = _owners;
        emit ConfigUpdated();
    }

    function setVolumeRewards(address _vr) external onlyOwner {
        volumeRewards = _vr;
        emit ConfigUpdated();
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero addr");
        owner = newOwner;
    }

    function emergencyWithdraw(address token, uint256 amount) external onlyOwner {
        IERC20V2(token).transfer(owner, amount);
    }
}

contracts/acuav2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from,address to,uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract H2OUniversalStakingFinal {

    uint256 constant BPS = 10000;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable H2O;
    address public immutable UTH2;

    constructor(address _h2o, address _uth2){
        H2O=_h2o;
        UTH2=_uth2;
        owners.push(msg.sender);
        ownerShares[msg.sender]=1;
        totalOwnerVipShares=1;
    }

    // -------------------------------------------------
    // OWNERS
    // -------------------------------------------------

    address[] public owners;
    mapping(address=>uint256) public ownerShares;
    uint256 public totalOwnerVipShares;

    modifier onlyOwner(){
        bool ok=false;
        for(uint i=0;i<owners.length;i++){
            if(owners[i]==msg.sender) ok=true;
        }
        require(ok,"not owner");
        _;
    }

    // -------------------------------------------------
    // FEES
    // -------------------------------------------------

    uint256 public depositFeeBps = 500;
    uint256 public withdrawFeeBps = 500;
    uint256 public claimFeeBps = 1000;

    // -------------------------------------------------
    // STAKING CORE
    // -------------------------------------------------

    uint256 public totalStaked;
    uint256 public rewardRate;
    uint256 public periodFinish;
    uint256 public lastUpdate;
    uint256 public rewardPerTokenStored;

    struct User {
        uint256 balance;
        uint256 rewardDebt;
        uint256 pending;
    }

    mapping(address=>User) public users;

    function rewardPerToken() public view returns(uint256){
        if(totalStaked==0) return rewardPerTokenStored;
        return rewardPerTokenStored + ((block.timestamp-lastUpdate)*rewardRate*1e18/totalStaked);
    }

    function _updateReward(address acc) internal{
        rewardPerTokenStored=rewardPerToken();
        lastUpdate=block.timestamp;
        if(acc!=address(0)){
            users[acc].pending = earned(acc);
            users[acc].rewardDebt = rewardPerTokenStored;
        }
    }

    function earned(address acc) public view returns(uint256){
        User storage u=users[acc];
        return (u.balance*(rewardPerToken()-u.rewardDebt)/1e18)+u.pending;
    }

    // -------------------------------------------------
    // PERMIT2 STAKE
    // -------------------------------------------------

    function stake(IPermit2.PermitTransferFrom calldata permit,bytes calldata sig) external {
        _updateReward(msg.sender);

        uint256 amount = permit.permitted.amount;

        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this),amount),
            msg.sender,
            sig
        );

        uint256 fee = amount*depositFeeBps/BPS;
        uint256 net = amount-fee;

        ownerVipPool += fee;

        users[msg.sender].balance+=net;
        totalStaked+=net;
    }

    function unstake(uint256 amount) external {
        _updateReward(msg.sender);
        require(users[msg.sender].balance>=amount);

        uint256 fee = amount*withdrawFeeBps/BPS;
        uint256 net = amount-fee;

        ownerVipPool+=fee;

        users[msg.sender].balance-=amount;
        totalStaked-=amount;

        IERC20(H2O).transfer(msg.sender,net);
    }

    // -------------------------------------------------
    // REFERRAL SYSTEM (GLOBAL POOL)
    // -------------------------------------------------

    mapping(address=>address) public referrerOf;
    mapping(address=>uint256) public refCount;
    uint256 public totalRefShares;

    function registerReferrer(address ref) external {
        require(referrerOf[msg.sender]==address(0));
        require(ref!=msg.sender);
        referrerOf[msg.sender]=ref;
        refCount[ref]+=1;
        totalRefShares+=1;
    }

    uint256 public referralPool;
    mapping(address=>uint256) public refRewardDebt;
    uint256 public refPerShare;

    function _updateRefPool(uint256 amount) internal {
        if(totalRefShares==0){ ownerVipPool+=amount; return;}
        refPerShare += amount*1e18/totalRefShares;
    }

    function claimRefRewards() external {
        uint256 share = refCount[msg.sender];
        require(share>0);
        uint256 pending = share*(refPerShare-refRewardDebt[msg.sender])/1e18;
        refRewardDebt[msg.sender]=refPerShare;
        IERC20(H2O).transfer(msg.sender,pending);
    }

    // -------------------------------------------------
    // OWNER + VIP POOL
    // -------------------------------------------------

    uint256 public ownerVipPool;
    uint256 public ownerVipPerShare;
    mapping(address=>uint256) public ownerVipDebt;

    function _updateOwnerVip(uint256 amount) internal {
        ownerVipPerShare += amount*1e18/totalOwnerVipShares;
    }

    function claimOwnerVip() external {
        uint256 share = ownerShares[msg.sender];
        require(share>0);
        uint256 pending = share*(ownerVipPerShare-ownerVipDebt[msg.sender])/1e18;
        ownerVipDebt[msg.sender]=ownerVipPerShare;
        IERC20(H2O).transfer(msg.sender,pending);
    }

    // -------------------------------------------------
    // VIP SUBSCRIPTION (UTH2)
    // -------------------------------------------------

    uint256 public vipPrice = 1e18;
    uint256 public vipDuration = 30 days;
    mapping(address=>uint256) public vipExpire;

    function buyVIP(uint256 months_) external {
        IERC20(UTH2).transferFrom(msg.sender,address(this),vipPrice*months_);
        uint256 start = vipExpire[msg.sender]>block.timestamp?vipExpire[msg.sender]:block.timestamp;
        vipExpire[msg.sender]=start+vipDuration*months_;

        ownerShares[msg.sender]+=1;
        totalOwnerVipShares+=1;
    }

    // -------------------------------------------------
    // CLAIM REWARDS (SPLIT FEES)
    // -------------------------------------------------

    function claimRewards() external {
        _updateReward(msg.sender);

        uint256 reward = users[msg.sender].pending;
        require(reward>0);
        users[msg.sender].pending=0;

        uint256 fee = reward*claimFeeBps/BPS;
        uint256 net = reward-fee;

        uint256 refPart = fee/2;
        uint256 vipPart = fee-refPart;

        _updateRefPool(refPart);
        _updateOwnerVip(vipPart);

        IERC20(H2O).transfer(msg.sender,net);
    }

    // -------------------------------------------------
    // FUND REWARDS
    // -------------------------------------------------

    function depositRewards(uint256 amount) external onlyOwner{
        IERC20(H2O).transferFrom(msg.sender,address(this),amount);
        rewardRate = amount / 365 days;
        lastUpdate = block.timestamp;
        periodFinish = block.timestamp + 365 days;
    }
}

contracts/AcuaVolumeRewards.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/**
 * @title AcuaVolumeRewards
 * @notice Monthly UTH2 rewards based on USDC swap volume.
 *         Volume is recorded by the authorised AcuaSwapRouter.
 *         Tiers and rewards are fully configurable by owner.
 *
 * Period: 30-day rolling windows (block.timestamp / PERIOD).
 * Each tier is claimable once per period once the threshold is reached.
 */
contract AcuaVolumeRewards {

    // ─── Constants ────────────────────────────────────────────────────────────
    address public constant UTH2   = 0x9eA8653640E22A5b69887985BB75d496dc97022a;
    uint256 public constant PERIOD = 30 days;
    uint256 public constant MAX_TIERS = 8;

    // ─── Config ───────────────────────────────────────────────────────────────
    address public owner;
    address public swapRouter;
    uint256 public numTiers = 4;

    /// @notice Tier thresholds in USDC-6-decimals (1e6 = 1 USDC)
    uint256[8] public tierThresholds;
    /// @notice UTH2 reward per tier in 18-decimals
    uint256[8] public tierRewards;

    // ─── State ────────────────────────────────────────────────────────────────
    mapping(address => mapping(uint256 => uint256)) public volume;
    mapping(address => mapping(uint256 => mapping(uint256 => bool))) public claimed;
    uint256 public totalDistributed;

    // ─── Events ───────────────────────────────────────────────────────────────
    event VolumeRecorded(address indexed user, uint256 indexed monthId, uint256 added, uint256 total);
    event RewardClaimed(address indexed user, uint256 indexed monthId, uint256 uth2Amount);
    event Funded(address indexed by, uint256 amount);
    event TiersUpdated(uint256 numTiers);

    modifier onlyOwner()  { require(msg.sender == owner,       "Not owner");       _; }
    modifier onlyRouter() { require(msg.sender == swapRouter || msg.sender == owner, "Not authorized"); _; }

    // ─── Constructor ──────────────────────────────────────────────────────────
    constructor(address _swapRouter) {
        owner      = msg.sender;
        swapRouter = _swapRouter;

        // Default 4-tier table
        tierThresholds[0] = 1_000_000;       // 1 USDC
        tierThresholds[1] = 10_000_000;      // 10 USDC
        tierThresholds[2] = 100_000_000;     // 100 USDC
        tierThresholds[3] = 1_000_000_000;   // 1000 USDC

        tierRewards[0] = 0.0001 ether;
        tierRewards[1] = 0.001  ether;
        tierRewards[2] = 0.01   ether;
        tierRewards[3] = 0.1    ether;
    }

    // ─── Period helpers ───────────────────────────────────────────────────────

    function currentMonth() public view returns (uint256) {
        return block.timestamp / PERIOD;
    }

    /**
     * @notice Returns timing info for the current period.
     * @return monthId         Current 30-day period index
     * @return periodStart     Unix timestamp when current period began
     * @return periodEnd       Unix timestamp when current period ends
     * @return secondsLeft     Seconds until next period reset
     */
    function getPeriodInfo() external view returns (
        uint256 monthId,
        uint256 periodStart,
        uint256 periodEnd,
        uint256 secondsLeft
    ) {
        monthId     = currentMonth();
        periodStart = monthId * PERIOD;
        periodEnd   = (monthId + 1) * PERIOD;
        secondsLeft = periodEnd > block.timestamp ? periodEnd - block.timestamp : 0;
    }

    /**
     * @notice Returns all active tiers in one call.
     * @return thresholds  Array of USDC-6-dec threshold amounts (length = numTiers)
     * @return rewards     Array of UTH2-18-dec reward amounts (length = numTiers)
     */
    function getAllTiers() external view returns (
        uint256[] memory thresholds,
        uint256[] memory rewards
    ) {
        thresholds = new uint256[](numTiers);
        rewards    = new uint256[](numTiers);
        for (uint256 i; i < numTiers; ++i) {
            thresholds[i] = tierThresholds[i];
            rewards[i]    = tierRewards[i];
        }
    }

    // ─── Record swap volume ───────────────────────────────────────────────────

    function recordSwap(address user, uint256 usdcAmount) external onlyRouter {
        uint256 monthId = currentMonth();
        volume[user][monthId] += usdcAmount;
        emit VolumeRecorded(user, monthId, usdcAmount, volume[user][monthId]);
    }

    // ─── Claim rewards ────────────────────────────────────────────────────────

    function claimRewards(uint256 monthId) external {
        address user    = msg.sender;
        uint256 userVol = volume[user][monthId];
        require(userVol > 0, "No volume this month");

        uint256 totalUTH2;
        for (uint256 i; i < numTiers; ++i) {
            if (userVol >= tierThresholds[i] && !claimed[user][monthId][i]) {
                claimed[user][monthId][i] = true;
                totalUTH2 += tierRewards[i];
            }
        }

        require(totalUTH2 > 0, "All tiers claimed or not reached");

        uint256 available = IERC20(UTH2).balanceOf(address(this));
        require(available >= totalUTH2, "Insufficient UTH2 - wait for restock");

        totalDistributed += totalUTH2;
        IERC20(UTH2).transfer(user, totalUTH2);
        emit RewardClaimed(user, monthId, totalUTH2);
    }

    // ─── View helpers ─────────────────────────────────────────────────────────

    /**
     * @notice Pending rewards for user at given monthId.
     * @return uth2Amount   Claimable UTH2
     * @return userVolume   Accumulated USDC-6-dec volume
     * @return tierStatus   0=not reached, 1=claimable, 2=already claimed (length = numTiers)
     */
    function pendingRewards(address user, uint256 monthId)
        external view
        returns (uint256 uth2Amount, uint256 userVolume, uint8[] memory tierStatus)
    {
        userVolume = volume[user][monthId];
        tierStatus = new uint8[](numTiers);
        for (uint256 i; i < numTiers; ++i) {
            if (claimed[user][monthId][i]) {
                tierStatus[i] = 2;
            } else if (userVolume >= tierThresholds[i]) {
                tierStatus[i] = 1;
                uth2Amount += tierRewards[i];
            }
        }
    }

    function pendingNow(address user)
        external view
        returns (uint256 uth2Amount, uint256 userVolume, uint8[] memory tierStatus)
    {
        return this.pendingRewards(user, currentMonth());
    }

    // ─── Fund UTH2 ────────────────────────────────────────────────────────────

    function fundUTH2(uint256 amount) external {
        require(amount > 0, "Zero amount");
        IERC20(UTH2).transferFrom(msg.sender, address(this), amount);
        emit Funded(msg.sender, amount);
    }

    // ─── Admin ────────────────────────────────────────────────────────────────

    function setSwapRouter(address _router) external onlyOwner {
        swapRouter = _router;
    }

    /**
     * @notice Update tier configuration.
     * @param n           Number of active tiers (1-8)
     * @param thresholds  USDC-6-dec thresholds (must be ascending)
     * @param rewards     UTH2-18-dec rewards per tier
     */
    function setTiers(
        uint256 n,
        uint256[8] calldata thresholds,
        uint256[8] calldata rewards
    ) external onlyOwner {
        require(n >= 1 && n <= MAX_TIERS, "Bad tier count");
        for (uint256 i = 1; i < n; ++i) {
            require(thresholds[i] > thresholds[i-1], "Thresholds not ascending");
        }
        numTiers = n;
        for (uint256 i; i < MAX_TIERS; ++i) {
            tierThresholds[i] = thresholds[i];
            tierRewards[i]    = rewards[i];
        }
        emit TiersUpdated(n);
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero addr");
        owner = newOwner;
    }

    function emergencyWithdraw(uint256 amount) external onlyOwner {
        IERC20(UTH2).transfer(owner, amount);
    }

    function adminRecordVolume(address user, uint256 usdcAmount) external onlyOwner {
        uint256 monthId = currentMonth();
        volume[user][monthId] += usdcAmount;
        emit VolumeRecorded(user, monthId, usdcAmount, volume[user][monthId]);
    }
}

contracts/H2OVIPStandalone.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/**
 * @title H2OVIPStandalone
 * @notice Contrato VIP totalmente independiente del stake de H2O.
 *
 * Flujo de suscripción
 * --------------------
 * 1. Usuario firma un Permit2 en World App (sin approve).
 * 2. buyVIPWithPermit2() jala UTH2 del usuario a este contrato.
 * 3. El UTH2 queda aquí — el owner lo retira con withdrawUTH2() cuando quiera.
 * 4. El usuario queda registrado como holder de rewards (1 share, primera compra).
 *
 * Flujo de rewards (H2O)
 * -----------------------
 * 1. El owner fondea el contrato con H2O via depositRewards().
 * 2. Se fija rewardRate = amount / 365 days → rewards/segundo.
 * 3. Los holders acumulan H2O por segundo proporcional a sus shares.
 * 4. Cada usuario reclama 24/7 llamando a claimOwnerVip().
 *
 * Notas
 * -----
 * - vipPrice es configurable por el owner.
 * - 1 share por usuario (primera compra únicamente).
 * - Sin conexión al contrato de stake de H2O.
 */
contract H2OVIPStandalone {

    uint256 constant SCALE   = 1e18;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable UTH2;
    address public immutable H2O;

    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(address _uth2, address _h2o) {
        UTH2  = _uth2;
        H2O   = _h2o;
        owner = msg.sender;
    }

    // ── VIP subscription tracking ─────────────────────────────────────────

    uint256 public constant vipDuration = 30 days;
    uint256 public vipPrice = 1e18; // 1 UTH2 por mes (18 decimales)

    mapping(address => uint256) public vipExpire;

    // ── H2O reward pool (Synthetix-style per-share) ───────────────────────

    uint256 public rewardRate;     // H2O wei/segundo (total para todos los holders)
    uint256 public periodFinish;   // timestamp en que terminan los rewards
    uint256 public lastUpdate;     // último update del pool
    uint256 public rewardPerShare; // H2O acumulado por share × SCALE

    mapping(address => uint256) public holderShares;
    uint256 public totalHolderShares;
    mapping(address => uint256) public rewardDebt; // snapshot de rewardPerShare por usuario

    // ── Reward math ────────────────────────────────────────────────────────

    function lastTimeRewardApplicable() public view returns (uint256) {
        return block.timestamp < periodFinish ? block.timestamp : periodFinish;
    }

    function _rewardPerShare() internal view returns (uint256) {
        if (totalHolderShares == 0) return rewardPerShare;
        uint256 ts = lastTimeRewardApplicable();
        if (ts <= lastUpdate) return rewardPerShare;
        return rewardPerShare + (ts - lastUpdate) * rewardRate * SCALE / totalHolderShares;
    }

    function _updatePool() internal {
        rewardPerShare = _rewardPerShare();
        lastUpdate = lastTimeRewardApplicable();
    }

    /// @notice Reward H2O pendiente de reclamar para un usuario
    function pendingReward(address user) external view returns (uint256) {
        uint256 share = holderShares[user];
        if (share == 0) return 0;
        uint256 rps = _rewardPerShare();
        if (rps <= rewardDebt[user]) return 0;
        return share * (rps - rewardDebt[user]) / SCALE;
    }

    // ── Buy VIP via Permit2 ────────────────────────────────────────────────

    /**
     * @notice Comprar o extender suscripción VIP usando UTH2 via Permit2.
     *         World App maneja la firma — sin approve() previo.
     *
     * @param months_  Meses a comprar (1-12)
     * @param permit   Permit2 struct
     * @param sig      Firma Permit2 de World App
     */
    function buyVIPWithPermit2(
        uint256 months_,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata sig
    ) external {
        require(months_ > 0 && months_ <= 12, "invalid months");
        uint256 cost = vipPrice * months_;
        require(permit.permitted.token == UTH2, "wrong token");
        require(permit.permitted.amount >= cost, "amount too low");

        // Jalar UTH2 del usuario a este contrato via Permit2
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this), cost),
            msg.sender,
            sig
        );
        // UTH2 queda aquí — owner lo retira con withdrawUTH2()

        // Actualizar expiración VIP
        uint256 start = vipExpire[msg.sender] > block.timestamp
            ? vipExpire[msg.sender]
            : block.timestamp;
        vipExpire[msg.sender] = start + vipDuration * months_;

        // Registrar como holder de rewards (solo en la primera compra)
        if (holderShares[msg.sender] == 0) {
            _updatePool();
            holderShares[msg.sender] = 1;
            totalHolderShares += 1;
            rewardDebt[msg.sender] = rewardPerShare;
        }
    }

    // ── Claim H2O rewards ─────────────────────────────────────────────────

    /**
     * @notice Reclamar H2O acumulado del pool de rewards VIP.
     *         Las recompensas se acumulan por segundo — se puede reclamar 24/7.
     */
    function claimOwnerVip() external {
        _updatePool();

        uint256 share = holderShares[msg.sender];
        require(share > 0, "not a VIP holder");

        uint256 pending = share * (rewardPerShare - rewardDebt[msg.sender]) / SCALE;
        require(pending > 0, "nothing to claim");

        rewardDebt[msg.sender] = rewardPerShare;
        IERC20(H2O).transfer(msg.sender, pending);
    }

    // ── View helpers ──────────────────────────────────────────────────────

    function isVIP(address user) external view returns (bool) {
        return vipExpire[user] > block.timestamp;
    }

    // ── Admin ─────────────────────────────────────────────────────────────

    /**
     * @notice Fondear el contrato con H2O para pagar rewards VIP.
     *         Los H2O se distribuyen linealmente en 365 días.
     *         Solo el owner puede llamar esto.
     * @param amount  Cantidad de H2O (18 decimales) a depositar
     */
    function depositRewards(uint256 amount) external onlyOwner {
        IERC20(H2O).transferFrom(msg.sender, address(this), amount);
        _updatePool();
        rewardRate    = amount / 365 days;
        lastUpdate    = block.timestamp;
        periodFinish  = block.timestamp + 365 days;
    }

    /**
     * @notice Retirar UTH2 acumulado de las suscripciones VIP.
     * @param amount  Cantidad a retirar (0 = retirar todo)
     */
    function withdrawUTH2(uint256 amount) external onlyOwner {
        if (amount == 0) {
            amount = IERC20(UTH2).balanceOf(address(this));
        }
        require(amount > 0, "no UTH2");
        IERC20(UTH2).transfer(owner, amount);
    }

    /**
     * @notice Cambiar el precio de la suscripción VIP en UTH2.
     * @param newPrice  Precio por mes en UTH2 (18 decimales)
     */
    function setVipPrice(uint256 newPrice) external onlyOwner {
        require(newPrice > 0, "price > 0");
        vipPrice = newPrice;
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "zero address");
        owner = newOwner;
    }

    /// @notice Recuperar cualquier token enviado al contrato por error.
    function rescueToken(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
}

contracts/H2OVIPSubscription.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IH2OStaking {
    function buyVIP(uint256 months_) external;
    function claimOwnerVip() external;
    function vipPrice() external view returns (uint256);
    function ownerShares(address) external view returns (uint256);
}

/**
 * @title H2OVIPSubscription
 * @notice Permit2 connector for the H2O staking VIP subscription.
 *
 * Problem it solves
 * -----------------
 * The staking contract's buyVIP() uses ERC20.transferFrom, which requires a
 * prior approve() call. In World App, approve() is unreliable and causes tx
 * failures. This contract bridges the gap:
 *   1. User signs ONE Permit2 message in World App (no approve needed).
 *   2. This contract receives the UTH2 from the user via Permit2.
 *   3. This contract calls staking.buyVIP() using its own pre-approved UTH2
 *      allowance → staking contract gets the UTH2 and gives this contract
 *      an ownerShare in its VIP fee pool.
 *   4. This contract records the subscription for the actual user.
 *
 * Rewards flow (no owner deposits required)
 * ------------------------------------------
 * Every time staking users claim rewards, 5% of the claim fee accumulates in
 * the staking contract's ownerVipPool. This contract has ownerShares there.
 * When a user calls claimOwnerVip() here, this contract:
 *   a) Calls staking.claimOwnerVip() to pull its earned H2O from the pool.
 *   b) Distributes the collected H2O proportionally to VIP holders.
 */
contract H2OVIPSubscription {

    uint256 constant SCALE   = 1e18;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable UTH2;
    address public immutable H2O;
    address public immutable STAKING;

    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(address _uth2, address _h2o, address _staking) {
        UTH2    = _uth2;
        H2O     = _h2o;
        STAKING = _staking;
        owner   = msg.sender;
        // Pre-approve: allow the staking contract to pull UTH2 from this contract.
        // This is what makes staking.buyVIP() work without a user approve().
        IERC20(_uth2).approve(_staking, type(uint256).max);
    }

    // ── VIP subscription tracking ─────────────────────────────────────────

    uint256 public constant vipDuration = 30 days;
    mapping(address => uint256) public vipExpire;

    // ── H2O reward pool for VIP holders ───────────────────────────────────

    mapping(address => uint256) public holderShares;
    uint256 public totalHolderShares;
    uint256 public rewardPerShare;
    mapping(address => uint256) public rewardDebt;

    // ── Read vipPrice from staking (single source of truth) ───────────────

    function vipPrice() public view returns (uint256) {
        return IH2OStaking(STAKING).vipPrice();
    }

    // ── Buy VIP with Permit2 ───────────────────────────────────────────────

    /**
     * @notice Buy or extend VIP subscription using UTH2 via Permit2.
     *         World App handles the signature — NO prior approve() needed.
     *
     * @param months_  Months to purchase (1-12)
     * @param permit   Permit2 struct: { permitted:{token,amount}, nonce, deadline }
     * @param sig      Permit2 signature from World App
     */
    function buyVIPWithPermit2(
        uint256 months_,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata sig
    ) external {
        require(months_ > 0 && months_ <= 12, "invalid months");
        uint256 cost = vipPrice() * months_;
        require(permit.permitted.token == UTH2, "wrong token");
        require(permit.permitted.amount >= cost, "amount too low");

        // 1. Pull UTH2 from user to this contract via Permit2 (no approve needed)
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this), cost),
            msg.sender,
            sig
        );

        // 2. Forward UTH2 to the staking contract by calling buyVIP.
        //    The staking contract pulls UTH2 from this contract using the
        //    pre-approved allowance set in the constructor.
        //    As a result, this contract gains +1 ownerShare in staking's VIP pool.
        IH2OStaking(STAKING).buyVIP(months_);

        // 3. Record the actual user's subscription expiry in this contract.
        uint256 start = vipExpire[msg.sender] > block.timestamp
            ? vipExpire[msg.sender]
            : block.timestamp;
        vipExpire[msg.sender] = start + vipDuration * months_;

        // 4. Register user as a reward holder (first purchase only).
        //    Pull any pending H2O from staking first so current holders get it,
        //    then snapshot rewardPerShare for the new holder.
        if (holderShares[msg.sender] == 0) {
            _pullFromStaking();
            holderShares[msg.sender] = 1;
            totalHolderShares += 1;
            rewardDebt[msg.sender] = rewardPerShare;
        }
    }

    // ── Collect H2O from staking and distribute to VIP holders ───────────

    /**
     * @dev Calls claimOwnerVip on the staking contract to collect this
     *      contract's share of the H2O fee pool, then updates rewardPerShare.
     */
    function _pullFromStaking() internal {
        if (IH2OStaking(STAKING).ownerShares(address(this)) == 0) return;
        uint256 before = IERC20(H2O).balanceOf(address(this));
        // claimOwnerVip may revert if pending == 0, so we use try/catch
        try IH2OStaking(STAKING).claimOwnerVip() {} catch {}
        uint256 gained = IERC20(H2O).balanceOf(address(this));
        if (gained > before && totalHolderShares > 0) {
            rewardPerShare += (gained - before) * SCALE / totalHolderShares;
        }
    }

    /**
     * @notice Public trigger — anyone can call to push the latest staking
     *         rewards into the VIP pool (e.g. before checking pendingReward).
     */
    function pullFromStaking() external {
        _pullFromStaking();
    }

    // ── Claim H2O rewards ─────────────────────────────────────────────────

    /**
     * @notice Claim your accumulated H2O rewards from the VIP pool.
     *         Commissions accumulate automatically as staking users claim;
     *         you can claim here whenever you want.
     */
    function claimOwnerVip() external {
        _pullFromStaking();

        uint256 share = holderShares[msg.sender];
        require(share > 0, "not a VIP holder");

        uint256 pending = share * (rewardPerShare - rewardDebt[msg.sender]) / SCALE;
        require(pending > 0, "nothing to claim");

        rewardDebt[msg.sender] = rewardPerShare;
        IERC20(H2O).transfer(msg.sender, pending);
    }

    // ── View helpers ──────────────────────────────────────────────────────

    function pendingReward(address user) external view returns (uint256) {
        uint256 share = holderShares[user];
        if (share == 0) return 0;
        return share * (rewardPerShare - rewardDebt[user]) / SCALE;
    }

    function isVIP(address user) external view returns (bool) {
        return vipExpire[user] > block.timestamp;
    }

    // ── Admin ─────────────────────────────────────────────────────────────

    function setOwner(address newOwner) external onlyOwner {
        owner = newOwner;
    }

    /// @notice Safety: recover any tokens sent to this contract by mistake.
    function rescueToken(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
}

